'use client'

import { useState } from 'react'
import styles from './login.module.css'

export default function LoginPage() {
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState('')
  const apiUrl = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:8787'

  async function handleGoogleSignIn() {
    setLoading(true)
    setError('')

    try {
      // BetterAuth social sign-in requires POST with JSON body
      const res = await fetch(`${apiUrl}/api/auth/sign-in/social`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          provider: 'google',
          callbackURL: `${window.location.origin}/chat`,
        }),
        credentials: 'include',
      })

      const data = await res.json()

      if (data.url) {
        // BetterAuth returns the OAuth redirect URL
        window.location.href = data.url
      } else if (data.redirect) {
        window.location.href = data.redirect
      } else {
        setError('Could not start Google sign-in. Check your API configuration.')
        setLoading(false)
      }
    } catch (err) {
      setError('Could not connect to the API. Make sure the API server is running.')
      setLoading(false)
    }
  }

  return (
    <main className={styles.main}>
      <div className={styles.card}>
        <h1 className={styles.heading}>PatraSaar</h1>
        <p className={styles.tagline}>Legal clarity, distilled.</p>

        <button
          onClick={handleGoogleSignIn}
          className={styles.googleButton}
          disabled={loading}
        >
          {loading ? (
            <span className={styles.spinner} />
          ) : (
            <svg viewBox="0 0 24 24" width="20" height="20" aria-hidden="true" suppressHydrationWarning>
              <path
                d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92a5.06 5.06 0 0 1-2.2 3.32v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.1z"
                fill="#4285F4"
              />
              <path
                d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z"
                fill="#34A853"
              />
              <path
                d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z"
                fill="#FBBC05"
              />
              <path
                d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z"
                fill="#EA4335"
              />
            </svg>
          )}
          {loading ? 'Redirecting...' : 'Sign in with Google'}
        </button>

        {error && <p className={styles.error}>{error}</p>}

        <p className={styles.disclaimer}>
          By signing in, you agree that PatraSaar provides legal information for educational
          purposes only, not legal advice.
        </p>
      </div>
    </main>
  )
}
